    },
    {
      "source_requirement": "The system allows multiple attempts if the OTP does not match initially.",
      "rewritten_requirement": "The system shall allow multiple attempts for OTP authentication if the initial attempt fails."
    },
    {
      "source_requirement": "Once authenticated successfully, the user can view items based on different categories.",
      "rewritten_requirement": "The system shall enable users to view items based on different categories once they are successfully authenticated."
    },
    {
      "source_requirement": "The system allows users to select items for purchase.",
